// ── VIMEO TOKEN ───────────────────────────────────────────────
const VIMEO_TOKEN = '1b9d7ff9117d2258a0ed0728406403d7';
// ─────────────────────────────────────────────────────────────
const inp = $input.first().json;
function extractVimeoId(val) {
  if (!val) return null;
  const m = String(val).match(/(?:vimeo\.com\/(?:video\/)?)(\d+)|^(\d+)$/);
  return m ? (m[1] || m[2]) : null;
}
const vimeo_id = extractVimeoId(inp.vimeo_id || inp.source_value || '');
return [{json:{
  ...inp,
  vimeo_token:  VIMEO_TOKEN,
  vimeo_id,
  sys_url:  'https://raw.githubusercontent.com/jeremieborrotzu-blip/Ressources_Loc_OSS/main/01_prompts/a7_caption_localizer_system.txt',
  user_url: 'https://raw.githubusercontent.com/jeremieborrotzu-blip/Ressources_Loc_OSS/main/01_prompts/srt_agent_user_template.txt'
}}];

const inp = $('Vimeo Config').first().json;
const res = $input.first().json;
const tracks = res.data || [];
const srcLang = (inp.source_language || 'fr').toLowerCase().substring(0,2);
const track = tracks.find(t => (t.language||'').toLowerCase().startsWith(srcLang) && ['subtitles','captions'].includes(t.type))
           || tracks.find(t => (t.language||'').toLowerCase().startsWith(srcLang))
           || tracks[0];
if (!track) return [{json:{...inp, track_found:false, error_msg:`No ${srcLang} track. Available: ${tracks.map(t=>t.language).join(',')||'none'}`}}];
return [{json:{...inp, track_found:true, track_link:track.link, track_language:track.language, track_type:track.type}}];

const inp       = $('Vimeo Config').first().json;
const sys_prompt= $('Load System Prompt').first().json.content || '';
const usr_tpl   = $('Load User Template').first().json.content || '';
const srt_raw   = $input.first().json.srt_raw || '';
const ft        = $('Find Source Track').first().json;

// Parse SRT/VTT
function parseSubtitles(raw) {
  const clean = raw.replace(/^WEBVTT[^\n]*/,'').trim();
  const blocks = clean.split(/\n\n+/);
  const segs = [];
  for (const block of blocks) {
    const lines = block.trim().split('\n').filter(l=>l.trim());
    if (lines.length < 2) continue;
    let idx = segs.length+1, timecode='', texts=[];
    for (const line of lines) {
      if (/-->/.test(line)) timecode = line.trim();
      else if (/^\d+$/.test(line) && !timecode) idx = parseInt(line);
      else if (timecode) texts.push(line.trim());
    }
    if (timecode && texts.length) segs.push({index:idx, timecode, text:texts.join(' ')});
  }
  return segs;
}

const segments = parseSubtitles(srt_raw);
const glossary_arr = (inp.a2_glossary || []).slice(0,30).map(g=>`${g.source_term||g.term}→${g.target_term||g.translation}`);

// Fill user template
const decision_log_summary = inp.decision_log
  ? JSON.stringify(Object.entries(inp.decision_log).slice(0,10)).substring(0,500)
  : '{}';

const user_msg = usr_tpl
  .replace('{{course_id}}',       inp.source_course_id||'')
  .replace('{{video_id}}',        inp.vimeo_id||'')
  .replace('{{source_language}}', inp.source_language||'fr')
  .replace('{{target_language}}', inp.target_language||'en-US')
  .replace('{{domain}}',          inp.detected_domain||'Tech')
  .replace('{{source_srt}}',      srt_raw.substring(0,6000))
  .replace('{{target_srt_draft}}','')
  .replace('{{common_glossary}}', glossary_arr.slice(0,15).join('; '))
  .replace('{{domain_glossary}}', glossary_arr.slice(15).join('; '))
  .replace('{{temp_glossary}}',   '')
  .replace('{{html_decision_log}}', decision_log_summary)
  .replace('{{score_target}}',    '90');

return [{json:{
  ...inp,
  parsed_segments: segments,
  segment_count: segments.length,
  srt_raw,
  system_prompt: sys_prompt,
  user_message:  user_msg,
  openai_payload: {
    model: 'gpt-5.2-2025-12-11',
    messages: [{role:'system',content:sys_prompt},{role:'user',content:user_msg}],
    max_completion_tokens: Math.min(16000, Math.max(2000, segments.length * 100)),
    temperature: 0.1
  }
}}];

const inp    = $('Build Message').first().json;
const openai = $input.first().json;
if (openai.error) return [{json:{...inp, srt_error:'OpenAI: '+(openai.error.message||openai.error)}}];

const content = openai?.choices?.[0]?.message?.content || '';
let a7_out = {};
try {
  const m = content.match(/\{[\s\S]*\}/);
  a7_out = JSON.parse(m ? m[0] : content);
} catch(e) { return [{json:{...inp, srt_error:'JSON parse failed', raw:content.substring(0,300)}}]; }

// Rebuild SRT from revised_srt (if A7 returned it) or from segments
let srt_final = '';
if (a7_out.revised_srt) {
  srt_final = a7_out.revised_srt;
} else if (a7_out.segments) {
  const orig = inp.parsed_segments || [];
  srt_final = orig.map((seg,i) => {
    const t = a7_out.segments.find(s=>s.index===seg.index)||a7_out.segments[i];
    return `${seg.index}\n${seg.timecode}\n${t?t.text:seg.text}`;
  }).join('\n\n') + '\n';
}

const dir   = inp.direction || 'fr_enUS';
const fname = `${inp.target_course_id}_sub_${inp.vimeo_id}_${dir}.srt`;
const gh_path = `07_runs/${inp.source_course_id}/output/transcripts/${fname}`;

return [{json:{
  ...inp,
  srt_final,
  srt_b64:   Buffer.from(srt_final).toString('base64'),
  gh_path,  fname,
  a7_status: a7_out.status || 'pass',
  a7_score:  a7_out.score_total || null,
  lip_sync_flags: a7_out.lip_sync_flags || [],
  decision_log_srt: a7_out.decision_log || [],
  tokens_used: openai?.usage?.total_tokens || 0
}}];

